import Stripe from"stripe";const stripe=new Stripe(process.env.STRIPE_SECRET_KEY,{apiVersion:"2024-06-20"});export async function handler(e){if("POST"!==e.httpMethod)return{statusCode:405,body:"Method Not Allowed"};const t=e.headers["stripe-signature"]||e.headers["Stripe-Signature"];if(!t)return{statusCode:400,body:"Missing Stripe-Signature header"};const s=process.env.STRIPE_WEBHOOK_SECRET;if(!s)return{statusCode:500,body:"Missing STRIPE_WEBHOOK_SECRET"};let o;try{const r=e.isBase64Encoded?Buffer.from(e.body,"base64").toString("utf8"):e.body;o=stripe.webhooks.constructEvent(r,t,s)}catch(e){return{statusCode:400,body:`Webhook Error: ${e.message}`}}return"checkout.session.completed"===o.type&&o.data.object,"checkout.session.async_payment_succeeded"===o.type&&o.data.object,{statusCode:200,body:"ok"}}